// ============================================
// PROFANITY DETECTION + SENTIMENT ANALYSIS
// Mirrors the DRC Google Apps Script logic
// ============================================

const input = $input.first().json;

// --- Profanity Detection ---
const PROFANITY_LIST = [
  'fuck', 'shit', 'damn', 'ass', 'bitch', 'bastard', 'crap',
  'dick', 'piss', 'hell', 'douche', 'asshole', 'bullshit',
  'motherfucker', 'wtf', 'stfu', 'lmao', 'dumbass'
];

function checkProfanity(text) {
  if (!text) return { flagged: false, words: [] };
  const lower = text.toLowerCase();
  const matched = [];
  for (const word of PROFANITY_LIST) {
    const regex = new RegExp(`(?<![a-z])${word}(?![a-z])`, 'gi');
    if (regex.test(lower)) matched.push(word);
  }
  return { flagged: matched.length > 0, words: matched };
}

// --- Sentiment Analysis ---
const SENTIMENT_RULES = [
  {
    category: 'Churn Risk',
    priority: 'HIGH',
    color: '#FF4444',
    triggers: ['cancel', 'cancellation', 'leaving', 'leave', 'switching',
               'switch', 'going elsewhere', 'not coming back', 'done with',
               'not renewing', 'ending my', 'quit', 'dropping']
  },
  {
    category: 'Unresponsive',
    priority: 'HIGH',
    color: '#FF4444',
    triggers: ['no one answers', 'nobody answers', 'never heard back',
               'no response', 'not responding', 'ignoring', 'ignored',
               'ghosting', 'ghosted', 'waiting for days', 'called multiple times',
               'emailed multiple times', 'still waiting']
  },
  {
    category: 'Dissatisfaction',
    priority: 'MEDIUM',
    color: '#FF8C00',
    triggers: ['ridiculous', 'unacceptable', 'disappointed', 'disappointing',
               'frustrating', 'frustrated', 'terrible', 'horrible', 'awful',
               'worst', 'waste of time', 'waste of money', 'rip off',
               'unprofessional', 'incompetent', 'useless']
  },
  {
    category: 'Urgency',
    priority: 'LOW',
    color: '#FFD700',
    triggers: ['asap', 'as soon as possible', 'immediately', 'urgent',
               'urgently', 'right away', 'time sensitive', 'deadline',
               'need this today', 'need this now', 'rush', 'critical']
  }
];

function checkSentiment(text) {
  if (!text) return { priority: 'Neutral', category: '', triggers: [], color: '#FFFFFF' };
  const lower = text.toLowerCase();

  for (const rule of SENTIMENT_RULES) {
    const matched = [];
    for (const trigger of rule.triggers) {
      const regex = new RegExp(`(?<![a-z])${trigger.replace(/\s+/g, '\\s+')}(?![a-z])`, 'gi');
      if (regex.test(lower)) matched.push(trigger);
    }
    if (matched.length > 0) {
      return {
        priority: rule.priority,
        category: rule.category,
        triggers: matched,
        color: rule.color
      };
    }
  }

  return { priority: 'Neutral', category: '', triggers: [], color: '#333333' };
}

// --- Run checks ---
const textToAnalyze = `${input.senderChallenge || ''} ${input.senderName || ''}`;
const profanity = checkProfanity(textToAnalyze);
const sentiment = checkSentiment(textToAnalyze);

return [{
  json: {
    ...input,
    languageFlag: profanity.flagged ? 'FLAGGED' : 'Clean',
    flaggedWords: profanity.words.join(', ') || '',
    sentimentPriority: sentiment.priority,
    sentimentCategory: sentiment.category,
    sentimentTriggers: sentiment.triggers.join(', ') || '',
    sentimentColor: sentiment.color,
    requiresAttention: sentiment.priority === 'HIGH' || profanity.flagged
  }
}];

